sp_theme.css_variables:
/* COLORS */

/* whites */
$white: #FFF;

/* mtg dark green */
$mtg-dark-purple: #32213A;
$mtg-medium-tan: #D1CAA1;

/* grays */
$gray: #5B5E62;
$gray-light: #8C8E91;
$gray-lighter: #BDBFC0;
$gray-lightest: #DEDFE0;
$gray-lightest-tint-2: #F6F7F8;
$gray-lightest-tint-1: #EDEFF1;
$gray-dark: #494B4E;
$gray-darker: #37383B;

/* greens */
$black-green: #282E27;
$green: #007E6F;
$green-faded: #90C8C1;

/* oranges */
$neon-carrot: #FFA348;

/* yellows */
$yellow: #F2B705;

/* blacks */
$black: #131B22;

/* whites */
$white-smoke: #F1F6F1;

/* reds */
$red: #AB1C1C;
$red-dark: #891616;
$red-light: #F7E8E8;
$red-faded: #D99A9A;

/* grey */
$grey-dark: #232323;

/* Bootstrap colors/brand colors */
$brand-primary: $grey-dark;
$brand-secondary: $neon-carrot;
$brand-tertiary: $white-smoke;
$brand-success: $servos-teal-darker;
$brand-info: $servos-mid-blue;
$brand-warning: $servos-orange;
$brand-danger: $red;

/* other colors */
$link-color: $brand-info;
$btn-ghost: #007698;
$btn-ghost-hover: #E6F3F6;
$btn-ghost-active: #00517D;
$link-hover-color: $servos-dark-blue;
$text-color: $white;
$text-muted: $gray-light;
$link-color-dark: $servos-light-blue-light;
$link-color-dark-hover: #60BDE8;
$link-color-disabled: $gray-light;
$link-color-dark-visited: #6CB0FF;
$table-border-color: $gray-lightest;
$progress-bar-start: $servos-light-blue-lightest;

/* footer */
$footer-color: $grey-dark;

/* header */
/*$sp-navbar-height: 72px !default;
$sp-logo-y: 17px !default;
$sp-logo-max-height: 18px !default;
$sp-logo-margin-x: 16px !default;
$sp-logo-x: 17px !default;
$navbar-inverse-bg: $brand-secondary !default;
$navbar-inverse-link-color: $white !default;
$navbar-inverse-link-hover-color: white !default;
$navbar-inverse-link-hover-bg: $brand-primary !default;
$sp-navbar-divider-color: #FAFAFA; !default;
$navbar-brand-bg: white !default;
$navbar-accent-bg: #F9B900 !default;
$mega-menu-box-shadow: 0px 6px 10px rgba(0, 0, 0, 0.16) !default;
$sp-space--sm: 8px !default;
$sp-space--xxs: 2px !default;
$sp-space--md: 16px !default; */

/* spacing */
$single-space: 8px;
$double-space: 16px;
$triple-space: 24px;
$quad-space: 32px;
$quintuple-space: 40px;



/* ==============================
   DEBUG BLOCK
   ============================== */

.mtg-debug {
  margin-top: 2rem;
  padding: 1rem;
  border: 1px dashed #ccc;
  background: #fafafa;
}

.mtg-debug__title {
  font-size: 0.9rem;
  margin-bottom: 0.5rem;
  color: $brand-primary;
}

.mtg-debug__pre {
  font-size: 0.75rem;
  max-height: 300px;
  overflow: auto;
  background: $brand-primary;
  color: #0f0;
  padding: 0.75rem;
  border-radius: 4px;
}

/* ==============================
   MTG GRID SYSTEM
   ============================== */

.mtg-grid {
  display: flex;
  flex-direction: column;
  gap: 1rem;
  color:black;
}

/* Controls */
.mtg-grid__controls {
  font-size: 0.9rem;
  color: $brand-primary;
}

/* Container */
.mtg-grid__container {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(calc(220px * var(--mtg-card-scale)), 1fr));
  gap: calc(1rem * var(--mtg-card-scale));
}

/* Grid Item */
.mtg-grid__item {
  display: flex;
}

/* ==============================
   CARD COMPONENT
   ============================== */

.mtg-card {
  display: inline-flex; /* shrink to fit content */
  flex-direction: column;
  padding: 0.5rem; /* optional spacing around image */

  background: transparent;
  border-radius: 8px;

  transition: all 0.2s ease;
  outline: none;
  cursor: pointer;
}

/* Hover + Focus moved to whole card to ensure foil and children scale together */
.mtg-card:focus,
.mtg-card:hover {
  outline: none;
}

/* Header */
.mtg-card__header {
  display:flex;
  justify-content: center;
  align-items: center;
  margin-bottom: 0.5rem;
}

.mtg-card__title {
  font-size: 1rem;
  font-weight: 600;
  margin: 0;
  color:$brand-secondary;
}

/* Body */
.mtg-card__body {
  display: inline-block;
  justify-content: center;
  align-items: center;
  flex-grow: 1;
  position: relative;

}

/* Card scaling via CSS variable set on the grid. Rather than scaling the image
   alone (which can cause hover transform overrides and foil mismatch), scale
   the entire `.mtg-card` so layout remains consistent and overlay follows. For
   large mode increase the grid min column width to prevent overlap. */
.mtg-grid {
  --mtg-card-scale: 1;
}

.mtg-grid--small {
  --mtg-card-scale: 0.65;
}

.mtg-grid--medium {
  --mtg-card-scale: 1;
}

.mtg-grid--large {
  --mtg-card-scale: 1.25;
}

/* Increase grid cell minimum for large mode so scaled cards have room */
.mtg-grid--large .mtg-grid__container {
  grid-template-columns: repeat(auto-fill, minmax(calc(220px * var(--mtg-card-scale)), 1fr));
  gap: calc(1.25rem * var(--mtg-card-scale));
}

/* Ensure each grid item reserves extra space proportional to scale so the
   visually-scaled card never intrudes into its neighbor's area. */
.mtg-grid__item {
  padding: calc(0.75rem * var(--mtg-card-scale));
  box-sizing: border-box;
  overflow: visible; /* allow hover shadow/scale to render without clipping */
}

/* Provide more breathing room between controls and the grid when cards are large */
.mtg-grid__search {
  margin-bottom: calc(1.5rem * var(--mtg-card-scale));
}

.mtg-card {
  transform-origin: center center;
  transform: none; /* base size provided by grid cell sizing */
  transition: transform 0.12s ease, box-shadow 0.12s ease;
  width: 100%;
  box-sizing: border-box;
}

.mtg-card:hover {
  transform: scale(1.06); /* always grow slightly relative to base */
  box-shadow: 0 8px 24px rgba(0,0,0,0.18);
}

.mtg-card__body {
  display: block;
}

.mtg-card__image {
  display: block;
  width: auto;      
  height: auto;     
  border-radius: 5%;
  object-fit: contain;
  max-width: 100%;  /* prevent overflow in smaller grids */
}

.mtg-card__foil {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;      /* Matches card image width */
  height: 100%;     /* Matches card image height */
  pointer-events: none; /* So overlay doesn’t block card interaction */
  z-index: 2;       /* On top of the card image */
  border-radius: 5%;
}


.mtg-card__desc {
  font-size: 0.875rem;
  color: $brand-secondary;
}

/* Footer */
.mtg-card__footer {
  display:flex;
  justify-content: center;
  align-items: center;
  margin-top: 0.75rem;
  font-size: 1.5rem;
  color: $brand-secondary;
}

/* ==============================
   MTG GRID SEARCH BAR
   ============================== */

.mtg-grid__search {
  display: flex;
  justify-content: center; /* center the search bar */
  margin-bottom: 1.5rem;
}

.mtg-search__form {
  display: flex;
  width: 100%;
  max-width: 400px;
  gap: 0.5rem;
}

.mtg-search__input {
  flex-grow: 1;
  padding: 0.5rem 0.75rem;
  border: 1px solid #ccc;
  border-radius: 6px;
  font-size: 0.9rem;
}

.mtg-search__input:focus {
  border-color: $brand-primary; /* Tailwind Blue-500 */
  outline: none;
  box-shadow: 0 0 0 2px rgba(59, 130, 246, 0.3);
}

.mtg-search__btn {
  padding: 0.5rem 1rem;
  border-radius: 6px;
  border: 1px solid #ccc;
  background: #f9f9f9;
  cursor: pointer;
  transition: background 0.2s ease;
}

.mtg-search__btn:hover {
  background: #eee;
}

.mtg-grid__results-count {
  font-size: 2rem;
  color: $brand-primary;
  margin-left: 1rem;
}

/* ==============================
   PAGINATION
   ============================== */

.mtg-grid__pagination {
  display: flex;
  justify-content: center;
  align-items: center;
  gap: 1rem;
  margin-bottom: 2rem;

  margin-top: 1rem;
}

.mtg-grid__page-info {
  font-size: 0.9rem;
  color: $brand-primary;
}

/* ==============================
   BUTTON
   ============================== */

.mtg-btn {
  padding: 0.5rem 1rem;
  border-radius: 6px;
  border: 1px solid #ccc;
  background: white;
  cursor: pointer;

  transition: background 0.2s ease;
}

.mtg-btn:hover {
  background: $brand-secondary;
}

.mtg-btn:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}

/* ==============================
   ADVANCED SEARCH MODAL
   ============================== */

.mtg-advanced-search {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  z-index: 9999;
  display: flex;
  justify-content: center;
  align-items: center;
  color:black;
}

/* Overlay */
.mtg-advanced-search__overlay {
  position: absolute;
  width: 100%;
  height: 100%;
  background: rgba(0,0,0,0.5);
}

/* Modal Content */
.mtg-advanced-search__content {
  position: relative;
  background: #fff;
  border-radius: 8px;
  padding: 1.5rem;
  width: 100rem;
  max-width: 90%;
  z-index: 10;
  display: flex;
  flex-direction: column;
}

/* Header */
.mtg-advanced-search__header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 1rem;
}

.mtg-advanced-search__close {
  background: transparent;
  border: none;
  font-size: 1.5rem;
  color:black;
  cursor: pointer;
}

/* Body with Columns */
.mtg-advanced-search__body {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 1rem;
  margin-bottom: 1rem;
}

.mtg-advanced-search__column {
  display: flex;
  flex-direction: column;
  gap: 0.75rem;
}

.mtg-advanced-search__column label {
  display: flex;
  flex-direction: column;
  font-size: 2rem;
  color: $brand-primary;
}
.mtg-advanced-search__colors {
  display: flex;
  flex-direction: row;
  gap: 1rem;
  flex-wrap: wrap;
}

.mtg-color-option {
  display: flex;
  align-items: center;
  gap: 0.4rem;
  cursor: pointer;
  font-size: 2rem;
}

.mtg-color-option input {
  cursor: pointer;
}

.mtg-color-option__icon {
  width: 2rem;
  height: 2rem;
}

.mtg-color-option__label {
  font-size: 2rem;
  display: inline-block;
  margin-left: 0.25rem;
}

.mtg-advanced-search__column input,
.mtg-advanced-search__column select {
  padding: 0.5rem;
  border: 1px solid #ccc;
  border-radius: 6px;
  width: 100%;
  box-sizing: border-box;
}

.mtg-advanced-search__column input[type="number"] {
  appearance: textfield;
  -webkit-appearance: textfield;
  -moz-appearance: textfield;
}

/* Footer Search Button */
.mtg-advanced-search__footer {
  display: flex;
  justify-content: center;
}

.mtg-advanced-search__submit {
  padding: 0.5rem 1.25rem;
  border-radius: 6px;
  background: $brand-secondary;
  color: black;
  border: none;
  cursor: pointer;
  font-weight: 600;
}

.mtg-advanced-search__submit:hover {
  background: $brand-secondary;
}
